/**
 * uiux-generator — audit
 *
 * CLI wrapper around lib/repo-ui-scan.js + lib/style-guide-html.js.
 * Scans a repo, extracts design tokens + component inventory, and renders a
 * style-guide.html — the full "receipts" document for a UI designer role.
 *
 * Usage:
 *   node audit.js --repo <path> --out <dir>
 *   node audit.js --repo . --out ./ui-audit
 *
 * Output:
 *   <out>/design-tokens.json      DTCG-format token tree
 *   <out>/component-inventory.md  Components ranked by usage
 *   <out>/ui-scan-summary.json    Raw findings
 *   <out>/style-guide.html        Visual style guide
 */

'use strict';

const fs = require('fs');
const path = require('path');
const scanner = require('./lib/repo-ui-scan');
const guide = require('./lib/style-guide-html');

function parseArgs(argv) {
  const out = { maxFiles: 2000 };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--repo') out.repo = argv[++i];
    else if (a === '--out') out.out = argv[++i];
    else if (a === '--max-files') out.maxFiles = parseInt(argv[++i], 10) || 2000;
    else if (a === '--skip-guide') out.skipGuide = true;
    else if (a === '-h' || a === '--help') out.help = true;
  }
  return out;
}

function printHelp() {
  console.log(`
audit — scan a repo for design tokens & components, then render a style guide

Usage:
  node audit.js --repo <path> --out <dir> [--max-files 2000] [--skip-guide]

Output:
  <out>/design-tokens.json      DTCG
  <out>/component-inventory.md  Components by usage
  <out>/ui-scan-summary.json    Raw audit
  <out>/style-guide.html        Visual guide (unless --skip-guide)
`);
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.help || !args.repo || !args.out) { printHelp(); process.exit(args.help ? 0 : 1); }

  const repo = path.resolve(args.repo);
  const outDir = path.resolve(args.out);
  fs.mkdirSync(outDir, { recursive: true });

  console.log(`Auditing ${repo} → ${outDir}`);
  const audit = scanner.auditRepo(repo, { maxFiles: args.maxFiles });
  const paths = scanner.saveAudit(audit, outDir);

  if (!args.skipGuide) {
    paths.styleGuide = guide.saveStyleGuide(audit, outDir);
  }

  console.log(`\nFiles scanned:    ${audit.totalFiles}`);
  console.log(`UI libraries:     ${audit.uiLibs.map(l => l.name).join(', ') || 'none'}`);
  console.log(`Tailwind config:  ${audit.tailwind ? audit.tailwind.source : 'no'}`);
  console.log(`Token buckets:    ${Object.entries(audit.buckets).map(([k, v]) => `${k}=${v}`).join(', ') || 'none'}`);
  console.log(`Components:       ${Object.keys(audit.components).length}`);
  console.log(`Inferred palette: ${JSON.stringify(audit.palette || {})}`);

  console.log('\nWritten:');
  for (const [k, p] of Object.entries(paths)) console.log(`  ${k.padEnd(12)} ${p}`);
}

main().catch((e) => { console.error(e); process.exit(1); });

/**
 * uiux-generator — inspire
 *
 * CLI wrapper around lib/fetch-inspiration.js. Fetch 1..N URLs, extract UI
 * tokens (colors / typography / spacing / radii / shadows), optionally grab a
 * screenshot (if Playwright is available), and save an inspiration bundle.
 *
 * Usage:
 *   node inspire.js --urls https://linear.app,https://stripe.com --out ./out
 *   node inspire.js --urls https://linear.app --out ./out --no-screenshot
 *   node inspire.js --url https://stripe.com --out ./out --name stripe
 *
 * Output (per URL):
 *   <out>/<name>/inspiration.json
 *   <out>/<name>/inspiration.md
 *   <out>/<name>/screenshot.png   (only if Playwright is installed)
 */

'use strict';

const path = require('path');
const fs = require('fs');
const inspiration = require('./lib/fetch-inspiration');

function parseArgs(argv) {
  const out = { urls: [], screenshot: true };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--url' || a === '--urls') {
      const v = argv[++i] || '';
      out.urls.push(...v.split(',').map(s => s.trim()).filter(Boolean));
    } else if (a === '--out') out.out = argv[++i];
    else if (a === '--name') out.name = argv[++i];
    else if (a === '--no-screenshot') out.screenshot = false;
    else if (a === '-h' || a === '--help') out.help = true;
  }
  return out;
}

function slugFromUrl(u) {
  try {
    const url = new URL(u);
    return (url.hostname + url.pathname).replace(/[^a-z0-9]+/gi, '-').replace(/^-+|-+$/g, '').toLowerCase().slice(0, 60);
  } catch { return 'site'; }
}

function printHelp() {
  console.log(`
inspire — fetch & analyze external UI for design inspiration

Usage:
  node inspire.js --urls <url1,url2> --out <dir> [--no-screenshot]
  node inspire.js --url <url> --out <dir> [--name <folder>]

Options:
  --urls <csv>       Comma-separated list of URLs to analyze
  --url  <url>       Shorthand for a single URL
  --out  <dir>       Output root (each URL gets its own subfolder)
  --name <string>    Override folder name for a single URL
  --no-screenshot    Skip Playwright screenshot (HTML+CSS only)

Notes:
  - HTML+CSS scraping is zero-dep.
  - Screenshot requires Playwright (\`npm i playwright\` + \`npx playwright install chromium\`).
    If not installed, the screenshot step is skipped gracefully.
`);
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.help || !args.urls.length || !args.out) { printHelp(); process.exit(args.help ? 0 : 1); }

  fs.mkdirSync(path.resolve(args.out), { recursive: true });

  for (const url of args.urls) {
    const name = args.urls.length === 1 && args.name ? args.name : slugFromUrl(url);
    const dir = path.join(path.resolve(args.out), name);
    console.log(`\n⟶ ${url}  →  ${dir}`);
    try {
      const analyzeOpts = {};
      if (args.screenshot) analyzeOpts.screenshotPath = path.join(dir, 'screenshot.png');
      fs.mkdirSync(dir, { recursive: true });
      const result = await inspiration.analyzeUrl(url, analyzeOpts);
      const out = inspiration.saveInspiration(result, dir);
      const palette = (result.tokens && result.tokens.palette) || {};
      console.log(`  palette: ${JSON.stringify(palette)}`);
      const t = result.tokens || {};
      console.log(`  tokens:  colors=${(t.colors || []).length} fonts=${(t.fonts || []).length} sizes=${(t.fontSizes || []).length}`);
      for (const [k, p] of Object.entries(out.files || {})) {
        if (p) console.log(`  ${k.padEnd(10)} ${p}`);
      }
    } catch (e) {
      console.error(`  ✖ ${e.message}`);
    }
  }
  console.log('\nDone.');
}

main().catch((e) => { console.error(e); process.exit(1); });

#!/usr/bin/env node
/**
 * preview — one-stop CLI for live preview + optional Cloudflare tunnel.
 *
 * Starts a detached serve.js daemon that watches the spec and rebuilds on
 * change. Browser clients receive WebSocket reload pushes. State is kept in
 * ~/.uiux-preview/<slug>.json so the agent can stop/status later.
 *
 * Usage:
 *   node preview.js start --spec <canvas.js> [--slug <name>] [--port 4455]
 *   node preview.js start --root <dir>       [--slug <name>] [--port 4455]
 *   node preview.js tunnel --slug <name>     [--auto-install]
 *   node preview.js stop   --slug <name>
 *   node preview.js status [--slug <name>]
 *   node preview.js list
 *   node preview.js install-cloudflared [--dry-run]
 *
 * Exit codes:
 *   0 = ok
 *   1 = user error (missing flag, etc.)
 *   2 = runtime failure
 */

'use strict';

const path = require('path');
const fs = require('fs');
const agent = require('./lib/preview-agent');

function parseFlags(argv) {
  const out = { _: [] };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a.startsWith('--')) {
      const key = a.slice(2);
      const next = argv[i + 1];
      if (!next || next.startsWith('--')) { out[key] = true; }
      else { out[key] = next; i++; }
    } else {
      out._.push(a);
    }
  }
  return out;
}

function printHelp() {
  console.log(`
preview — live-preview + tunnel CLI

Commands:
  start               Start a detached preview server
    --spec <file>       JS spec that exports a canvas (re-run on change)
    --root <dir>        Existing output directory (static watch)
    --slug <name>       Instance name (default: derived from spec/dir)
    --port <n>          Preferred port (auto-pick if taken)
    --host <h>          Bind host (default 127.0.0.1)

  tunnel              Open a Cloudflare Quick Tunnel for a running preview
    --slug <name>       Which preview (required)
    --auto-install      Install cloudflared if missing

  stop                Kill the preview (and its tunnel if any)
    --slug <name>       Which preview (required)

  status              Show one preview's state (or default slug)
    --slug <name>

  list                List all running previews

  install-cloudflared Print or run the platform install plan
    --dry-run           Print commands only

Examples:
  node preview.js start --spec ./my-canvas.js --slug odoo_sales
  node preview.js tunnel --slug odoo_sales --auto-install
  node preview.js stop   --slug odoo_sales
`);
}

function deriveSlug(flags) {
  if (flags.slug) return flags.slug;
  if (flags.spec) return path.basename(flags.spec, path.extname(flags.spec));
  if (flags.root) return path.basename(path.resolve(flags.root));
  return 'default';
}

function resolveServeScript() {
  // serve.js sits alongside this file
  return path.join(__dirname, 'serve.js');
}

async function cmdStart(flags) {
  if (!flags.spec && !flags.root) {
    console.error('✖ --spec or --root is required');
    process.exit(1);
  }
  const slug = deriveSlug(flags);
  const state = await agent.startPreview({
    specPath: flags.spec ? path.resolve(flags.spec) : null,
    outputDir: flags.root ? path.resolve(flags.root) : null,
    slug,
    port: flags.port ? parseInt(flags.port, 10) : undefined,
    host: flags.host || '127.0.0.1',
    serveScript: resolveServeScript(),
    preset: path.basename(path.dirname(__dirname)),
  });

  if (state.reused) {
    console.log(`● preview already running — slug=${state.slug}`);
  } else {
    console.log(`✔ preview started — slug=${state.slug} pid=${state.pid}`);
  }
  console.log(`  local    ${state.localUrl}`);
  console.log(`  logs     ${state.logOut}`);
  console.log(`  state    ${state.stateFile || agent.getState({ slug: state.slug }).stateFile || '(in state dir)'}`);
  console.log(`\nNext:`);
  console.log(`  • open ${state.localUrl} in browser (auto-reloads on spec change)`);
  console.log(`  • public URL  → node preview.js tunnel --slug ${state.slug} --auto-install`);
  console.log(`  • stop server → node preview.js stop   --slug ${state.slug}`);
}

async function cmdTunnel(flags) {
  if (!flags.slug) { console.error('✖ --slug is required'); process.exit(1); }
  const autoInstall = !!flags['auto-install'];

  try {
    const res = await agent.startTunnel({ slug: flags.slug, autoInstall });
    if (res.reused) console.log(`● tunnel already running`);
    else console.log(`✔ tunnel started — pid=${res.tunnelPid}`);
    console.log(`  public   ${res.publicUrl}`);
    const state = agent.getState({ slug: flags.slug });
    if (state) console.log(`  local    ${state.localUrl}`);
  } catch (e) {
    console.error(`✖ ${e.message}`);
    if (!autoInstall) {
      console.error(`\nRe-run with --auto-install to download cloudflared into ~/.local/bin/`);
    }
    process.exit(2);
  }
}

async function cmdStop(flags) {
  if (!flags.slug) { console.error('✖ --slug is required'); process.exit(1); }
  const res = agent.stopPreview({ slug: flags.slug });
  if (!res.stopped) console.log(`○ no preview found for slug=${flags.slug}`);
  else console.log(`✔ stopped — serve=${res.stoppedServe ? 'yes' : 'no'} tunnel=${res.stoppedTunnel ? 'yes' : 'no'}`);
}

async function cmdStatus(flags) {
  if (flags.slug) {
    const s = agent.getState({ slug: flags.slug });
    if (!s) { console.log(`○ no preview for slug=${flags.slug}`); return; }
    console.log(JSON.stringify(s, null, 2));
    return;
  }
  const all = agent.listPreviews();
  if (!all.length) { console.log('○ no previews running'); return; }
  for (const s of all) {
    const live = s.alive ? '●' : '○';
    const tun = s.tunnelAlive ? ` tunnel=${s.tunnel.publicUrl}` : '';
    console.log(`${live} ${s.slug.padEnd(24)} ${s.localUrl}${tun}  pid=${s.pid}`);
  }
}

async function cmdList() { return cmdStatus({}); }

async function cmdInstallCloudflared(flags) {
  const dry = !!flags['dry-run'];
  const already = await agent.ensureCloudflared({ autoInstall: false });
  if (already.ok) {
    console.log(`✔ cloudflared already available at ${already.path}`);
    return;
  }
  console.log('Manual install options (run these yourself if you prefer):');
  for (const h of already.hints) console.log(h);
  if (dry) {
    console.log(`\n(dry-run: not downloading anything)`);
    return;
  }
  console.log(`\nDownloading cloudflared to ~/.local/bin/ (userspace, no privileges)…`);
  const r = await agent.ensureCloudflared({ autoInstall: true });
  if (r.ok) {
    console.log(`\n✔ cloudflared installed at ${r.path}`);
    console.log(`  Add to PATH if needed:  export PATH="$HOME/.local/bin:$PATH"`);
  } else {
    console.error(`\n✖ download failed: ${r.error || 'unknown'}`);
    process.exit(2);
  }
}

// ────────────────────────────────────────── main

async function main() {
  const argv = process.argv.slice(2);
  if (!argv.length || argv[0] === '-h' || argv[0] === '--help') { printHelp(); process.exit(0); }
  const [cmd, ...rest] = argv;
  const flags = parseFlags(rest);

  switch (cmd) {
    case 'start':                return cmdStart(flags);
    case 'tunnel':               return cmdTunnel(flags);
    case 'stop':                 return cmdStop(flags);
    case 'status':               return cmdStatus(flags);
    case 'list':                 return cmdList();
    case 'install-cloudflared':  return cmdInstallCloudflared(flags);
    default:
      console.error(`unknown command: ${cmd}`);
      printHelp();
      process.exit(1);
  }
}

main().catch((e) => { console.error(e.stack || e.message); process.exit(2); });

/**
 * uiux-generator — serve
 *
 * CLI wrapper around lib/canvas-server.js. Starts a local web server that
 * hosts the rendered mockups.html + style-guide.html and live-reloads on
 * source changes.
 *
 * Usage:
 *   node serve.js --root <dir> [--port 4455]
 *   node serve.js --spec <spec.js> [--out <dir>] [--port 4455]
 *
 * Modes:
 *   --root <dir>      Serve an existing directory (expects mockups.html).
 *   --spec <file>     Path to a spec file (mockup SPEC export). Watches the
 *                     spec file's directory and re-runs `node <spec>` on
 *                     every change, then broadcasts reload.
 */

'use strict';

const fs = require('fs');
const path = require('path');
const { spawn } = require('child_process');
const server = require('./lib/canvas-server');

function parseArgs(argv) {
  const out = {};
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--root') out.root = argv[++i];
    else if (a === '--spec') out.spec = argv[++i];
    else if (a === '--out') out.out = argv[++i];
    else if (a === '--port') out.port = parseInt(argv[++i], 10);
    else if (a === '--host') out.host = argv[++i];
    else if (a === '--open') out.open = true;
    else if (a === '-h' || a === '--help') out.help = true;
  }
  return out;
}

function printHelp() {
  console.log(`
serve — live-reload web server for uiux-generator canvases

Usage:
  node serve.js --root <dir>                Serve an existing directory with mockups.html
  node serve.js --spec <spec.js>            Watch a spec file & re-run on change

Options:
  --port <num>     Port (default 4455)
  --host <ip>      Host (default 127.0.0.1)
  --out  <dir>     Override output directory when using --spec
  --open           (Reserved — not auto-opened here to keep zero deps)

Keyboard:
  Ctrl+C to stop.
`);
}

function runSpec(specPath) {
  return new Promise((resolve, reject) => {
    const proc = spawn(process.execPath, [specPath], { stdio: ['ignore', 'pipe', 'pipe'] });
    let out = '', err = '';
    proc.stdout.on('data', d => { out += d.toString(); process.stdout.write(d); });
    proc.stderr.on('data', d => { err += d.toString(); process.stderr.write(d); });
    proc.on('close', (code) => {
      if (code === 0) resolve({ out, err });
      else reject(new Error(`spec exited with code ${code}\n${err}`));
    });
  });
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.help || (!args.root && !args.spec)) { printHelp(); process.exit(args.help ? 0 : 1); }

  let rootDir;
  let watchList = [];
  let rebuild;

  if (args.spec) {
    const specPath = path.resolve(args.spec);
    if (!fs.existsSync(specPath)) throw new Error(`spec not found: ${specPath}`);

    // First build
    console.log(`Running spec: ${specPath}`);
    const first = await runSpec(specPath);
    // Try to infer the output dir from stdout ("Mockup bundle written to: <dir>")
    const dirMatch = first.out.match(/written to:\s*([^\n]+)/i);
    rootDir = args.out
      ? path.resolve(args.out)
      : (dirMatch ? dirMatch[1].trim() : path.join(path.dirname(specPath), 'prd-output'));
    watchList = [path.dirname(specPath)];
    rebuild = async () => {
      console.log(`[canvas-server] rebuilding ${path.basename(specPath)}…`);
      await runSpec(specPath);
    };
  } else {
    rootDir = path.resolve(args.root);
    watchList = [rootDir];
  }

  await server.start({
    rootDir,
    port: args.port || 4455,
    host: args.host || '127.0.0.1',
    watchPaths: watchList,
    rebuild,
    onReload: (changed) => console.log(`[canvas-server] reload — ${changed.slice(0, 3).join(', ')}${changed.length > 3 ? '…' : ''}`),
  });
}

main().catch((e) => { console.error(e); process.exit(1); });

#!/usr/bin/env node
/**
 * uiux-odoo-generator — generate-xml.js
 *
 * Load a canvas spec (as produced by any odoo-renderer call or hand-written
 * JSON) and render an Odoo module scaffold:
 *   <out>/<slug>/xml/
 *     __manifest__.py
 *     views/<module>_views.xml
 *     views/screens/<screen_id>.xml
 *
 * Usage:
 *   node generate-xml.js --spec path/to/screens.json [--out <dir>] [--module <name>]
 *   node generate-xml.js --example                         # render the bundled demo
 */

'use strict';

const fs = require('fs');
const path = require('path');
const x = require('./lib/odoo-xml');

function parseArgs(argv) {
  const out = {};
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--spec') out.spec = argv[++i];
    else if (a === '--out') out.out = argv[++i];
    else if (a === '--module') out.module = argv[++i];
    else if (a === '--example') out.example = true;
    else if (a === '-h' || a === '--help') out.help = true;
  }
  return out;
}

function printHelp() {
  console.log(`
generate-xml — render an Odoo XML scaffold from a canvas spec

Usage:
  node generate-xml.js --spec screens.json [--out <dir>] [--module <name>]
  node generate-xml.js --example

Options:
  --spec <path>    Path to screens.json (produced by saveOdooCanvas)
  --out  <dir>     Output directory (default: Cowork mnt/outputs/uiux-odoo-output/<slug>/xml)
  --module <name>  Module technical name override (default: derived from spec.slug)
  --example        Render the bundled example canvas
`);
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.help) { printHelp(); process.exit(0); }

  let canvas;
  if (args.example) {
    canvas = require('./example').canvas;
  } else if (args.spec) {
    const raw = fs.readFileSync(path.resolve(args.spec), 'utf8');
    canvas = JSON.parse(raw);
  } else {
    printHelp();
    process.exit(1);
  }

  const opts = {};
  if (args.out) opts.outputDir = path.resolve(args.out);
  if (args.module) opts.module = args.module;

  const out = x.saveOdooXml(canvas, opts);
  console.log('\n✔ XML scaffold generated');
  console.log(`  dir       ${out.dir}`);
  console.log(`  combined  ${out.files.combined}`);
  console.log(`  manifest  ${out.files.manifest}`);
  console.log(`  per-screen:`);
  for (const [id, p] of Object.entries(out.files.screens)) {
    console.log(`    ${id.padEnd(28)} ${p}`);
  }
  console.log('');
}

main().catch((e) => { console.error(e); process.exit(1); });

